// SPI Master Controller
module Comparator_16bit(
    input [15:0] A,
    input [15:0] B,
    output reg A_gt_B,
    output reg A_lt_B,
    output reg A_eq_B
);

// Combinational logic for comparison
always @(*) begin
    A_gt_B = (A > B);
    A_lt_B = (A < B);
    A_eq_B = (A == B);
end

endmodule
